mapper.select:
SELECT a.*, u.real_name AS creator_name FROM activity a LEFT JOIN sys_user u ON u.id = a.creator_id AND u.deleted = 0 WHERE a.deleted = 0
AND MATCH(a.title, a.description) AGAINST (#{keyword} IN BOOLEAN MODE)
AND a.status = #{status}
ORDER BY a.created_at DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM activity a WHERE a.deleted = 0
AND MATCH(a.title, a.description) AGAINST (#{keyword} IN BOOLEAN MODE)
AND a.status = #{status}
